+    #[test]
+    fn strict_json_missing_directed_allows_graph() {
+        let input = r#"{
+  "mode": "strict",
+  "graph_attrs": {},
+  "nodes": ["a", "b"],
+  "edges": [
+    { "left": "a", "right": "b", "attrs": {} }
+  ]
+}"#;
+
+        let mut engine = EdgeListEngine::strict();
+        let report = engine
+            .read_json_graph(input)
+            .expect("missing directed should not fail for Graph");
